def get_diagnostic_commands() -> list[dict[str, str]]:
    return DIAGNOSTIC_COMMANDS


def get_diagnostic_categories() -> list[str]:
    order = ["Windows", "Linux", "macOS", "Универсальные проверки"]
    return [item for item in order if any(command["os"] == item for command in DIAGNOSTIC_COMMANDS)]


def get_diagnostics_statistics() -> list[dict[str, Any]]:
    return [
        {"label": "Команды диагностики", "value": len(DIAGNOSTIC_COMMANDS), "note": "Безопасные справочные команды"},
        {"label": "Разделы ОС", "value": len(get_diagnostic_categories()), "note": "Windows, Linux, macOS и универсальные проверки"},
    ]
